var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_VAL_NULL`,text:{KOREA:`뭐야, 이 분위기는?`,JPN:`何？　いつもと雰囲気が違うけど。`,ENG:`What's up with this atmosphere?`,TWN:`搞什麼啊，這個氣氛？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_VAL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_VAL_NULL`,text:{KOREA:`......종신계약?`,JPN:`……終身契約？`,ENG:`A lifetime contract?`,TWN:`……終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_VAL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_VAL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_VAL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_VAL_NULL`,text:{KOREA:`그래. 나도 이 바닥에 들어온 지 얼마 안 된 신입이지만......`,JPN:`そうだね。私、この業界に入ってまだ日は浅いけど……`,ENG:`Okay. I'm pretty new to this industry, but...`,TWN:`是啦，我只是個剛來不久的新人沒錯……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_VAL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_VAL_NULL`,text:{KOREA:`사장님이 그렇게 나쁜 고용주는 아닌 것 같아.`,JPN:`社長が悪い雇い主じゃないってことは何となく判るんだ。`,ENG:`Even I can tell that you're not a bad employer.`,TWN:`但我覺得老闆不是那種惡質雇主。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_VAL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_VAL_NULL`,text:{KOREA:`요즘은 여기서 오래 일해도 괜찮겠다...... 라는 생각도 가끔씩은 들었고.`,JPN:`最近は、ここで長く働いてもいいかもって……思ったりもするしね。`,ENG:`In fact, I've been thinking maybe it wouldn't be too bad to work here for a long time.`,TWN:`在這裡長久工作應該也不錯……最近我偶爾會有這種想法。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_VAL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_VAL_NULL`,text:{KOREA:`뭐...... 잘 부탁할게.`,JPN:`まぁ……よろしく頼むよ。`,ENG:`Well, thank you for choosing me.`,TWN:`好吧……那就請多多指教了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_VAL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};